mapper.delete:
DELETE FROM blocks
WHERE block_code = #{blockCode}
AND user_code = #{userCode}

mapper.update:
UPDATE blocks
SET position = #{position}
WHERE block_code = #{blockCode}
AND user_code = #{userCode}

mapper.select:
SELECT * FROM ( SELECT i.issue_code AS issueCode, i.project_code AS projectCode, p.project_name AS projectName, i.title AS title, cc.code_name AS statusName, i.due_at AS dueAt, i.updated_at AS updatedAt FROM projects p JOIN ( SELECT pru.project_code FROM project_role_user pru WHERE pru.user_code = #{userCode}
UNION
SELECT gpr.project_code FROM "GROUP_MEMBER" gm JOIN "GR_PRO_ROLE" gpr ON gpr.gr_code = gm.gr_code WHERE gm.user_code = #{userCode} ) up ON up.project_code = p.project_code
JOIN issues i ON i.project_code = p.project_code
LEFT JOIN status st ON st.status_code = i.status_code
LEFT JOIN common_code cc ON cc.code_id = st.code_id /* OB1~OB5 */ AND cc.group_code = 'OB'
WHERE p.status = 'OD1' AND i.assignee_code = #{userCode}
ORDER BY i.updated_at DESC NULLS LAST, i.issue_code DESC ) WHERE ROWNUM <= #{limit}

SELECT * FROM ( SELECT i.issue_code AS issueCode, i.project_code AS projectCode, p.project_name AS projectName, i.title AS title, cc.code_name AS statusName, i.due_at AS dueAt, i.updated_at AS updatedAt FROM projects p JOIN ( SELECT pru.project_code FROM project_role_user pru WHERE pru.user_code = #{userCode}
UNION
SELECT gpr.project_code FROM "GROUP_MEMBER" gm JOIN "GR_PRO_ROLE" gpr ON gpr.gr_code = gm.gr_code WHERE gm.user_code = #{userCode} ) up ON up.project_code = p.project_code
JOIN issues i ON i.project_code = p.project_code
LEFT JOIN status st ON st.status_code = i.status_code
LEFT JOIN common_code cc ON cc.code_id = st.code_id AND cc.group_code = 'OB'
WHERE p.status = 'OD1' AND i.created_by_code = #{userCode}
ORDER BY i.updated_at DESC NULLS LAST, i.issue_code DESC ) WHERE ROWNUM <= #{limit}

SELECT * FROM ( SELECT n.notice_code AS noticeCode, n.project_code AS projectCode, p.project_name AS projectName, n.title AS title, n.created_at AS createdAt FROM projects p JOIN ( SELECT pru.project_code FROM project_role_user pru WHERE pru.user_code = #{userCode}
UNION
SELECT gpr.project_code FROM "GROUP_MEMBER" gm JOIN "GR_PRO_ROLE" gpr ON gpr.gr_code = gm.gr_code WHERE gm.user_code = #{userCode} ) up ON up.project_code = p.project_code
JOIN notices n ON n.project_code = p.project_code
WHERE p.status = 'OD1' ORDER BY n.created_at DESC ) WHERE ROWNUM <= #{limit}

SELECT TO_CHAR(i.due_at, 'yyyy-mm-dd') AS day, i.issue_code AS issueCode, i.project_code AS projectCode, p.project_name AS projectName, i.title AS title, i.due_at AS dueAt FROM projects p JOIN ( SELECT pru.project_code FROM project_role_user pru WHERE pru.user_code = #{userCode}
UNION
SELECT gpr.project_code FROM "GROUP_MEMBER" gm JOIN "GR_PRO_ROLE" gpr ON gpr.gr_code = gm.gr_code WHERE gm.user_code = #{userCode} ) up ON up.project_code = p.project_code
JOIN issues i ON i.project_code = p.project_code
WHERE p.status = 'OD1' AND i.due_at IS NOT NULL AND i.due_at >= #{from} AND i.due_at < #{to}
ORDER BY i.due_at ASC, i.issue_code ASC

SELECT * FROM ( SELECT i.issue_code AS issueCode, i.project_code AS projectCode, p.project_name AS projectName, i.title AS title, cc.code_name AS statusName, i.progress AS progress, i.due_at AS dueAt, i.updated_at AS updatedAt FROM issues i
JOIN projects p ON p.project_code = i.project_code
LEFT JOIN status st ON st.status_code = i.status_code
LEFT JOIN common_code cc ON cc.code_id = st.code_id AND cc.group_code = 'OB'
WHERE p.status = 'OD1' AND i.project_code = #{projectCode} AND i.assignee_code = #{assigneeCode}
ORDER BY i.updated_at DESC NULLS LAST, i.issue_code DESC ) WHERE ROWNUM <= #{limit}

SELECT * FROM ( SELECT i.issue_code AS issueCode, i.project_code AS projectCode, p.project_name AS projectName, i.title AS title, cc.code_name AS statusName, i.progress AS progress, i.due_at AS dueAt, i.updated_at AS updatedAt FROM issues i
JOIN projects p ON p.project_code = i.project_code
LEFT JOIN status st ON st.status_code = i.status_code
LEFT JOIN common_code cc ON cc.code_id = st.code_id AND cc.group_code = 'OB'
WHERE p.status = 'OD1' AND i.project_code = #{projectCode} AND i.created_by_code = #{creatorCode}
ORDER BY i.updated_at DESC NULLS LAST, i.issue_code DESC ) WHERE ROWNUM <= #{limit}
